 <?php
    @session_start();
    include("../../../config/main_function.php");
    $secure = "-%ekla!(m09)%1A7";
    $connection = connectDB($secure);

    $companyId = mysqli_real_escape_string($connection, $_POST['companyId']);

    $sql = "SELECT a.companyName,a.picture AS companyPicture,b.countryName,b.flag,a.city,
        (SELECT COUNT(c.branchId) FROM branch c WHERE c.companyId = a.companyId AND c.status = 1) AS AllBranch,
        (SELECT COUNT(d.branchId) FROM branch d WHERE d.companyId = a.companyId AND d.status = 1 AND d.financial_start_month IS NOT NULL) AS RegisterBranch,
        (SELECT COUNT(e.employeeId) FROM employee e WHERE e.companyId = a.companyId AND e.status = 1) AS employee,
        (SELECT COUNT(p.teamId) FROM company m 
        LEFT JOIN branch n ON m.companyId = n.companyId
        LEFT JOIN department o ON o.branchId = n.branchId
        LEFT JOIN team p ON p.departmentId = o.departmentId 
        WHERE m.companyId = a.companyId AND p.status = 1) AS teams
        FROM company a 
        LEFT JOIN country b ON a.countryId = b.countryId
        WHERE a.companyId = '$companyId'";
    $res = mysqli_query($connection, $sql);
    $row = mysqli_fetch_assoc($res);
    ?>

